// Script Continued Below
var tasking_System_Settings_Scripts = Class.create();
tasking_System_Settings_Scripts.prototype = {

	initialize: function() {

	},

	// STRY0099280
	SUSPENSE_DEFAULT_CURRENT_LOCAL_TIME: 0,
	SUSPENSE_DEFAULT_END_OF_DAY: 1,
	SUSPENSE_DEFAULT_CUSTOM_TIME: 2,
	// STRY0117523
	getEnableOfficeScheduleOverideValue: function(){
		var enableOfficeScheduleOverride = gs.getProperty('x_153465_discovert.Enable_Office_Schedule_Override');
		return enableOfficeScheduleOverride == 'true' || enableOfficeScheduleOverride==true;
	},

	// STRY0116257
	getTaskerDefaultView: function(){
		return gs.getProperty('x_153465_discovert.default_task_view');
	},

	// STRY0114645 - get all Top OUs for the list of offices provided
	getTopOUsForUser: function(userOffices) {
		var topOUs = [];
		var grUserOUs = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		for (i=0; i<userOffices.length; i++) {
			if(grUserOUs.get(userOffices[i])){
				topOUs.push(grUserOUs.getValue('u_top_ou'));				
			}
		}
		if (topOUs.length > 0){
			var au = new global.ArrayUtil();
			topOUs = au.unique(topOUs);
		}
		return topOUs;  
	},

	// DFCT0010732- Added lookup for OU Member Administrators 
	getMyOUMemberAdmins: function() {
		var offices = [];
		// DFCT0010752 
		var userMemAdminOUs = gs.getUserID() + '_DTech_MyMemberAdminOffices';
		var sessionMyMAOffices = gs.getSession().getClientData(userMemAdminOUs);
		if(!sessionMyMAOffices){
			var user = gs.getUserID();
			offices = this.getUserOUMemberAdmins(user);
			gs.getSession().putClientData(userMemAdminOUs, JSON.stringify(offices));
		} else {
			offices = JSON.parse(sessionMyMAOffices);
		}
		return offices;  
	},

	// DFCT0010732
	getUserOUMemberAdmins: function(user) {
		var offices = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grOUs.addQuery('can_manage_ou_members', 'true');
		grOUs.addQuery('office_member', user);
		grOUs.query();
		while(grOUs.next()){
			offices.push(grOUs.getValue('discover_office_hierarchy'));
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		} else {
			offices = ['none'];  // loads no OUs
		}
		return offices;  
	},

	// STRY0099280
	getDefaultTime: function(gr){
		var scs = this.systemControlSetting();
		var gdt = new GlideDateTime();
		var gDate = new GlideDate();
		var gTime = new GlideTime();
		var defaultDateTime;
		switch (scs.SuspenseDateDefault) {
			// If System Settings is set to Default, return the current time
			case this.SUSPENSE_DEFAULT_CURRENT_LOCAL_TIME:
				defaultDateTime = gdt.getDisplayValue();
				break;
				// If system setting is set to End of Day
			case this.SUSPENSE_DEFAULT_END_OF_DAY:
				switch (gr.getRecordClassName()){
					case 'x_153465_discovert_route_task_instance':
					case 'x_153465_discovert_route_tasks':
					case 'x_153465_discovert_discover_routing_template':
						// STRY0110317  - corrected an issue with this 
						// if Task, then if Primary Office is set, then check the Primary Assignee OU for an OU Schedule
						// if Task, no schedule on the Primary Office, then get the end of day based on the System Schedule
						gdt = new TaskerDurationCalculator().calculateEndOfDay(gr, gDate.getDisplayValue());
						defaultDateTime = gdt.getDisplayValue();
						// DFCT0010681 - if already passed the end of the day, add a day and get the end of day again.
						if (gdt.getNumericValue() < new GlideDateTime().getNumericValue()){
							var nextDay = new GlideDateTime(gDate.getValue());
							nextDay.addDaysUTC(1);
							gDate.setValue(nextDay.getValue());
							gdt = new TaskerDurationCalculator().calculateEndOfDay(gr, gDate.getDisplayValue());
							defaultDateTime = gdt.getDisplayValue();	
						}
						break;
					default:
						gTime.setDisplayValue("17:00:00");
						gdt.setDisplayValue(gDate.getDisplayValue() + " " + gTime.getDisplayValue());
						// DFCT0010681 - if already passed the end of the day, add a day
						if (gdt.getNumericValue() < new GlideDateTime().getNumericValue()){
							gdt = new TaskerDurationCalculator().calculateDateOfAddedBusinessDays(gr, 1, gDate.getDisplayValue());
							gdt.setDisplayValue(gdt.getLocalDate().getDisplayValue() + " " + gTime.getDisplayValue());
						}
						defaultDateTime = gdt.getDisplayValue();						
						break;
				}
				break;
			// if System Setting is set to Custom Date, then use the Custom date system property
			case this.SUSPENSE_DEFAULT_CUSTOM_TIME:
				gTime.setDisplayValue(scs.SuspenseDateTime);
				gdt.setDisplayValue(gDate.getDisplayValue() + " " + gTime.getDisplayValue());
				// DFCT0010681 - if already passed the end of the day, add a day
				if (gdt.getNumericValue() < new GlideDateTime().getNumericValue()){
					gdt = new TaskerDurationCalculator().calculateDateOfAddedBusinessDays(gr, 1, gDate.getDisplayValue());
					gdt.setDisplayValue(gdt.getLocalDate().getDisplayValue() + " " + gTime.getDisplayValue());
				}
				defaultDateTime = gdt.getDisplayValue();
				break;
		}
		return defaultDateTime;
	},

	//  STRY0099083 added new script for getting OUs that does not need a .join as it returns a string.
	// DFCT0010669 
	getOUsWhereIamAMember: function(){
		// DFCT0010752 
		var userMyOUs = gs.getUserID() + 'DTech_MyOffices';
		var sessionOffices = gs.getSession().getClientData(userMyOUs);
		var offices = [];
		if(!sessionOffices){		
			offices = this.getOUsWhereUserIsAMember(gs.getUserID());
			gs.getSession().putClientData(userMyOUs, JSON.stringify(offices));
		} else {
			offices = JSON.parse(sessionOffices);
		}
		return offices;
	},

	// DFCT0010669 
	getMyOUTaskManagers: function() {
		var offices = [];
		// DFCT0010752 
		var userMyTMOUs = gs.getUserID() + 'DTech_MyTaskMangementOffices';

		var sessionMyTMOffices = gs.getSession().getClientData(userMyTMOUs);
		if(!sessionMyTMOffices){
			var user = gs.getUserID();
			offices = this.getUserOUTaskManagers(user);
			gs.getSession().putClientData(userMyTMOUs, JSON.stringify(offices));
		} else {
			offices = JSON.parse(sessionMyTMOffices);
		}
		return offices;  
	},

	// This function returns the filter used to load all of the Templates for a user in the My Template folder
	// STRY0079658 added parent task to get restricted group
	getTemplateFilters: function(runOnly, parent_task) {
		var restrictedGroup = '';
		var restricted_group_s;
		if(parent_task){
			var grParentTask = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grParentTask.get(parent_task)){
				restrictedGroup = grParentTask.assignment_group + '';
				// STRY0095102 - get the nest list of groups
				// NOTE: may want to look at loading this one time for performance.  
				// If loading, build an object with top group as the key 
				// and the list of all groups under the top group as a comman delimitted string.
				restricted_group_s = new UserInfoScripts().getRestrictedGroupsAndDescendents(restrictedGroup);
			}
		}
		var templateFilters = {};
		templateFilters.hasMyTemplateRights = false;	
		templateFilters.hasOUTemplateRights = false;
		templateFilters.hasGlobalTemplateRights = false;

		// if user is a Task Administrator, they can run Global Templates
		var allFilter = "";
		var myFilter = "none";
		var ouFilter = "none";
		var globalFilter = "none";

		myFilter = this.getMyTemplateFilter(runOnly) + '';
		if (myFilter != '' ){
			templateFilters.hasMyTemplateRights = true;	
			// STRY0079658 add restricted group to my filter before addign to all b/c each is put together with NQ into all query.
			if(restrictedGroup != ''){
				// STRY0095102 - Use IN instead of equals to pull members from all parent groups
				myFilter = myFilter + '^u_restricted_groupIN' + restricted_group_s;
			}
			allFilter = myFilter;
		}
		templateFilters.myTemplateFilter = myFilter;
		ouFilter = this.getOUTemplateFilter(runOnly) + '';
		if (ouFilter != '' ){
			templateFilters.hasOUTemplateRights = true;
			if(allFilter.length !="")
				allFilter = allFilter + "^NQ";
			// STRY0079658 add restricted group to ou filter before addign to all b/c each is put together with NQ into all query.
			if(restrictedGroup != ''){
				// STRY0095102 - Use IN instead of equals to pull members from all parent groups
				ouFilter = ouFilter + '^u_restricted_groupIN' + restricted_group_s;
			}
			allFilter = allFilter + ouFilter;
		}
		templateFilters.ouFilter = ouFilter;
		globalFilter = this.getGlobalTemplateFilter(runOnly) + '';
		if (globalFilter != '' ){
			templateFilters.hasGlobalTemplateRights = true;
			if(allFilter.length !="")
				allFilter = allFilter + "^NQ";
			// STRY0079658 add restricted group to global filter before addign to all b/c each is put together with NQ into all query.
			if(restrictedGroup != ''){
				// STRY0095102 - Use IN instead of equals to pull members from all parent groups
				globalFilter = globalFilter + '^u_restricted_groupIN' + restricted_group_s;
			}
			allFilter = allFilter + globalFilter;
		}
		templateFilters.globalFilter = globalFilter;
		if (allFilter.length == 0) 
			allFilter = 'none';

		templateFilters.allTemplateFilter = allFilter;
		return templateFilters;
	},

	// This function returns the filter used to load all Templates for a user
	getAllTemplatesFilter: function(runOnly) {
		// STRY0079658 added parent task to get restricted group, no need to pass here, the calls for run from Task all go directly to the sub function.
		return this.getTemplateFilters(runOnly, '').allTemplateFilter;
	},
	// This function returns the filter used to load all of the Templates for a user in the My Template folder
	getMyTemplateFilter: function(runOnly) {
		// no changes for run only filter
		var UserPermissions = new UserInfoScripts();
		var addActive = '';

		// STRY0074534 Template Admins can read any template
		if(runOnly + '' != 'true'){
			var userIsTemplateAdmin =  UserPermissions.userHasProcessTemplateAdminRights() + '';
			if(userIsTemplateAdmin  == 'true'){
				return "process_level=my_process";
			}
		} else {
			// when run, always only show active templates, otherwise, let the user filter
			addActive  = '^u_active=true';
		}

		var userHasPersonalProcessRights = UserPermissions.userHasPersonalProcessRights() + '';
		if (userHasPersonalProcessRights == 'true')
			return "process_level=my_process^process_ownerDYNAMIC90d1921e5f510100a9ad2572f2b477fe" + addActive;
		else
			return "";
	},
	// This function returns the filter used to load all of the Templates for a user in the OU Template folder
	getOUTemplateFilter: function(runOnly) {
		var UserPermissions  = new UserInfoScripts();
		// STRY0074534 Template Admins can read any template
		var userIsTemplateAdmin =  UserPermissions.userHasProcessTemplateAdminRights() + '';
		var ousWhereTaskManager = this.getMyOUTaskManagers();
		var ousWhereTemplateDesigner = this.getMyOUTemplateDesigners(gs.getUserID());
		var filterOUs = ousWhereTaskManager;
		var addActive = '';
		if(runOnly + '' != 'true'){
			// STRY0074534 Template Admins can read any template
			if(userIsTemplateAdmin == 'true'){
				return "process_level=ou_process";
			}
			filterOUs = ousWhereTaskManager.concat(ousWhereTemplateDesigner);
			// if any OUs have been returned, parse to get only unique
			if (filterOUs.length > 0){
				var au = new global.ArrayUtil();
				filterOUs = au.unique(filterOUs);
			} 
		} else {
			// when run, always only show active templates, otherwise, let the user filter
			addActive  = '^u_active=true';
		}
		var userHasOUProcessRights = (filterOUs.length > 0) +'';
		if (userHasOUProcessRights == 'true')
			return "process_level=ou_process^process_ouIN" + filterOUs.join(',') + addActive;
		else
			return "";
	},
	// This function returns the filter used to load all of the Templates for a user in the Global Template folder
	getGlobalTemplateFilter: function(runOnly) {
		var UserPermissions = new UserInfoScripts();
		// STRY0074534 Template Admins can read any template
		var userIsTemplateAdmin =  UserPermissions.userHasProcessTemplateAdminRights() + '';
		var userIsTaskAdministrator =  UserPermissions.IsUserTaskAdministrator() + '';
		// STRY0112587
		var userIsTaskExecutive =  UserPermissions.IsUserTaskExecutive() + '';
		var userHasGlobalProcessRights =  UserPermissions.userHasGlobalProcessRights() + '';
		if(runOnly + '' != 'true'){
			// STRY0074534 Template Admins can read any template
			if(userIsTemplateAdmin == 'true'){
				return "process_level=global_process";
			}
			// STRY0112587
			if (userIsTaskAdministrator == 'true' || userIsTaskExecutive == 'true' ||  userHasGlobalProcessRights == 'true')
				return "process_level=global_process";
			else 
				return "";
		// STRY0112587
		} else if (userIsTaskAdministrator == 'true' || userIsTaskExecutive == 'true')
			return "process_level=global_process^u_active=true";
		else 
			return "";
	},

	systemControlSetting: function(){

		var systemControlSettings = {};
		// Until we have a system setting that can be used, this is hard coded.
		// once the system setting is available, get it here so all other functions use this alue
		var systemControlSettingValue =  gs.getProperty("x_153465_discovert.Organization Tasking Permission");
		if(systemControlSettingValue == 'Controlled (Divisional Organization)'){
			systemControlSettings.Controlled = true;
			systemControlSettings.Open = false;
		}
		else {
			systemControlSettings.Controlled = false;
			systemControlSettings.Open = true;
		}

		// STRY0072032
		var systemTreeStructureOrientation =  gs.getProperty("x_153465_discovert.Tree Structure Orientation");
		systemControlSettings.VerticalTree = (systemTreeStructureOrientation == 'Vertical Hierarchical Structure');
		systemControlSettings.HorizontalTree = (systemTreeStructureOrientation == 'Horizontal Hierarchical Structure');

		// STRY0099280
		systemControlSettings.SuspenseDateDefault = +gs.getProperty('x_153465_discovert.Suspense Time Preferences');
		systemControlSettings.SuspenseDateTime = gs.getProperty('x_153465_discovert.Suspense Custom due time');

		return systemControlSettings;
	},

	// Retrieve the OUs based on the user provided
	retrieveTaskOUs: function(user){
		// Check global setting (Open, Controlled, Flexible)

		var systemControlSetting = this.systemControlSetting(); 
		// Until we have a system setting that can be used, use the temp global setting
		if(systemControlSetting.Open == true){
			// send back no filter
			return [];
		}
		// Get all of the tasking ous for a person.  
		// Get all the OUs where the user is a Task Manager
		// Get all of the OUs the Task Manager can task in Controld Sstem setting
		// Check global setting (Open, Controlled, Flexible)
		// DFCT0010669 
		var userOffices = this.getUserOUTaskManagers(user);
		var allRelativeOffices = this.getAllRelatvieOUs(userOffices);

		// if you are no a task manager in any OUs then no OUs will have been returned yet.
		// load all OUs where this user is a member
		var userInOus = this.getOUsWhereUserIsAMember(user);
		var allOUs = allRelativeOffices.concat(userInOus);

		// STRY0112462
		var permissiveOffices = this.getPermissiveOUs();
		allOUs = allOUs.concat(permissiveOffices);

		// if any OUs have been returned, parse to get only unique
		if (allOUs.length > 0){
			var au = new global.ArrayUtil();
			allOUs = au.unique(allOUs);
		} 
		return allOUs;
	},

	// STRY0065247 - load the list of offices for template design fields
	retrieveTemplateOUs: function(user, templateLevel, templateOU){
		var UserPermissions  = new UserInfoScripts();
		var allOUs = ['none'];  // loads no OUs
		var userOffices = [];
		// Check global setting (Open, Controlled, Flexible)
		var systemControlSetting = this.systemControlSetting(); 
		// Until we have a system setting that can be used, use the temp global setting
		if(systemControlSetting.Open == true){
			return [];
		}

		// if Template Level is Global or personal, the user should have Global Template Desinger Permissions.
		// if the user has the right permissions show all OUs, if not show none.
		if (templateLevel == 'global_process'){
			if (UserPermissions.userHasGlobalProcessRights()) {
				return [];  // loads all OUs
			} else {
				return ['none'];  // loads no OUs
			}
		} else if (templateLevel == 'ou_process') {
			if (UserPermissions.userHasOUProcessRights(templateOU)) {
				// template level is OU and user has OU Template Designer rights
				// get all tasking OUs for this OU
				userOffices = [];
				userOffices.push(templateOU);
				allOUs = this.getAllRelatvieOUs(userOffices);
			} else {
				return ['none'];  // loads no OUs
			}
		} else if (templateLevel == 'my_process'){
			if (UserPermissions.IsUserTaskAdministrator() || UserPermissions.IsUserTaskExecutive()){
				return [];  // Loads all OUs
			} else {
				// Get all the OUs where the user is a Task Manager
				// DFCT0010669 
				userOffices = this.getUserOUTaskManagers(user);
				var allRelativeOffices = this.getAllRelatvieOUs(userOffices);
				// load all OUs where this user is a member
				var userInOus = this.getOUsWhereUserIsAMember(user);
				allOUs = allRelativeOffices.concat(userInOus);

				// STRY0112462
				var permissiveOffices = this.getPermissiveOUs();
				allOUs = allOUs.concat(permissiveOffices);
			}
		}
		// if any OUs have been returned, parse to get only unique
		if (allOUs.length > 0){
			var au = new global.ArrayUtil();
			allOUs = au.unique(allOUs);
		} 
		return allOUs;
	},

	getOUsWhereUserIsAMember: function(user) {
		var offices = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grOUs.addQuery('office_member', user);
		grOUs.query();
		while(grOUs.next()){  
			offices.push(grOUs.getValue('discover_office_hierarchy'));
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;  
	},

	// STRY0112462
	ouIsPermissive: function(ou){
		var isPermissive = false;
		// DFCT0010614
		if(gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions') != 'Off'){
			var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
			if(grOU.get(ou)){
				if(grOU.u_ou_is_permissive + '' == 'true' ){
					isPermissive = true;
				}
			}
		}
		return isPermissive;
	},

	getPermissiveOUs: function() {
		var offices = [];
		// DFCT0010614
		if(gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions') != 'Off'){
			var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
			grOUs.addQuery('u_ou_is_permissive', 'true');
			grOUs.query();
			while(grOUs.next()){
				offices.push(grOUs.getUniqueValue());
			}
			if (offices.length > 0){
				var au = new global.ArrayUtil();
				offices = au.unique(offices);
			}
		}
		return offices;  
	},

	// DFCT0010669 
	getUserOUTaskManagers: function(user) {
		var offices = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grOUs.addQuery('office_task_authority', 'true');
		grOUs.addQuery('office_member', user);
		grOUs.query();
		while(grOUs.next()){
			offices.push(grOUs.getValue('discover_office_hierarchy'));
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;  
	},

	getMyOUTemplateDesigners: function(user) {
		var offices = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grOUs.addQuery('has_ou_process_rights', 'true');
		grOUs.addQuery('office_member', user);
		grOUs.query();
		while(grOUs.next()){
			offices.push(grOUs.getValue('discover_office_hierarchy'));
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;  
	},

	getAllRelatvieOUs: function(userOffices){
		// userOffices is an array of sys_id strings
		var offices = [];
		var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		for (i=0; i<userOffices.length; i++) {
			if(grOU.get(userOffices[i])){
				// push parent onto offices
				if(!grOU.parent.nil()){
					var parentId = grOU.getValue('parent');
					offices.push(parentId);

					// Get siblings
					var grSiblings = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
					grSiblings.addQuery('parent', parentId);
					grSiblings.query();
					while(grSiblings.next()){
						offices.push(grSiblings.getValue('sys_id'));    
					}
				}
				// Get Descendents and add them to the siblings for each OU where I am a task Manager
				offices = this.getDescendents(userOffices[i], offices);
			}
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;
	},

	getDescendents: function(ou, offices){
		var grDescendents = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		grDescendents.addQuery('parent', ou);
		grDescendents.query();
		while(grDescendents.next()){
			offices.push(grDescendents.getValue('sys_id'));
			offices = this.getDescendents(grDescendents.getValue('sys_id'), offices);
		}
		return offices;
	},

	// ous can be one or an array
	retrieveMembersInOus: function(ous){
		var members = [];
		for (i=0; i<ous.length; i++) {
			var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
			//grOUs.addQuery('discover_office_hierarchy', 'IN', ous);
			grOUs.addQuery('discover_office_hierarchy', ous[i]);
			grOUs.query();
			while(grOUs.next()){
				members.push(grOUs.getValue('office_member'));
			}
		}
		if (members.length > 0){
			var au = new global.ArrayUtil();
			members = au.unique(members);
		}
		return members;
	},

	type: 'tasking_System_Settings_Scripts'
};
